data.solution:
N = int(input())
current = int(input())
gates = input().split()
operands = list(map(int, input().split()))

for gate, op in zip(gates, operands):
    if gate == "BUFFER":
        current = current
    elif gate == "NOT":
        current = 1 - current
    elif gate == "AND":
        current = current & op
    elif gate == "OR":
        current = current | op
    elif gate == "NAND":
        current = 1 - (current & op)
    elif gate == "NOR":
        current = 1 - (current | op)
    elif gate == "XOR":
        current = current ^ op
    elif gate == "XNOR":
        current = 1 - (current ^ op)

print(current)

data.constraints:
1 ≤ N ≤ 100
initialValue ∈ {0, 1}
operand[i] ∈ {0, 1}
Gates ∈ {BUFFER, NOT, AND, OR, NAND, NOR, XOR, XNOR}
